-- Zudio seed data — generated by scripts/generate_seed.js
-- Run AFTER migration: psql -d zudio_db -f src/seeds/seed.sql

-- Categories

-- Products (200)

-- Users (50 — passwords stored plaintext, intentional bug)

-- Coupons (20)

-- Orders and order_items
-- Using a DO block so we can loop and generate realistic volumes
DO $$
DECLARE
  uid       INT;
  ord_id    INT;
  num_orders INT;
  num_items  INT;
  prod_id    INT;
  qty        INT;
  uprice     NUMERIC(10,2);
  pname      VARCHAR;
  total      NUMERIC(10,2);
  statuses   TEXT[] := ARRAY['pending','confirmed','shipped','delivered','delivered','delivered'];
  addresses  TEXT[] := ARRAY[
    '12 Brigade Road, Bengaluru 560001',
    '45 Park Street, Kolkata 700016',
    '7 Linking Road, Mumbai 400050',
    '88 Connaught Place, New Delhi 110001',
    '23 Anna Salai, Chennai 600002',
    '56 MG Road, Pune 411001',
    '9 Jubilee Hills, Hyderabad 500033',
    '3 CG Road, Ahmedabad 380009',
    '77 Residency Road, Bengaluru 560025',
    '14 Salt Lake, Kolkata 700064'
  ];
  seed      INT := 0;
BEGIN
  FOR uid IN 1..50 LOOP
    num_orders := 5 + (uid * 3 + 7) % 11;  -- 5 to 15
    FOR o IN 1..num_orders LOOP
      seed := seed + 1;
      VALUES (
        uid,
        0,
        0,
        addresses[(seed % 10) + 1],
        statuses[(seed % 6) + 1],
        NOW() - ((seed % 365) || ' days')::INTERVAL
      ) RETURNING id INTO ord_id;

      total := 0;
      num_items := 2 + (seed * 17 + uid) % 7;  -- 2 to 8
      FOR i IN 1..num_items LOOP
        seed := seed + 1;
        prod_id := (seed * 31 + uid * 7 + i * 13) % 200 + 1;
        qty     := 1 + (seed + i) % 3;

        SELECT price, name INTO uprice, pname FROM products WHERE id = prod_id;

        VALUES (ord_id, prod_id, pname, uprice, qty, uprice);

        total := total + uprice * qty;
      END LOOP;

      UPDATE orders SET total_amount = total WHERE id = ord_id;
    END LOOP;
  END LOOP;
END $$;

-- end of seed